#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 dir = vec2(q1,q2);
vec2 d = vec2(q4,q5);
vec2 uv1 = .1*(GetBlur3(vUv.xy)*GetPixel(vUv))+ vec2(vUv.x+dir.x*d.x,vUv.y+dir.y*d.y);
    ret = texture( sampler_main, uv1 ).xyz;
    ret +=(.002* (texture(sampler_main, uv1).yxy));
    // darken (decay) over uTime
    ret *= 0.98; //or try: ret -= 0.004;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv1 = GetPixel(vUv)*uTexSize.zw;
uv1+=.1*GetBlur1(vUv);


//You can change the speed and direction of rotation by changing this variable
float rot=.5;

//This variable defines the center of rotation (cx, cy)
vec2 cxy=vec2(.5,.5);

vec2 xymod=uv1-cxy;
vec2 xy1=0;
vec2 warp=0;

//Rotate xy plane
xy1.x=sin(uTime*rot)*xymod.x-cos(uTime*rot)*xymod.y;
xy1.y=cos(uTime*rot)*xymod.x+sin(uTime*rot)*xymod.y;

vec2 rt=(xy1);
vec2 mod=mix(uv1, rt, .5);

vec3 tex = texture(sampler_fc_main, mod).xyz;

ret+=tex;


uv1.x+=.2*GetBlur2(vUv+vRadius*audioLow);
uv1.y+=-.1*GetBlur3(vUv+1/sin(vAngle*4)*.3*(audioLow+audioMid+audioHigh));
    ret = texture(sampler_main,.5* vUv-2*uv1).xyz;

ret.xy+=GetPixel(uv1)-GetBlur2(vUv);
ret.yz+=GetPixel(vUv)+GetBlur3(uv1);
ret.zx+=texture(sampler_fw_main,.5*vUv);

    ret *= 2.00; //gamma
ret=lum(ret)*sin(audioLow)*.6+ret*cos(audioLow)*.4;



  fragColor = ret;
}
